// Google TTS возвращает audioContent в base64 (MP3)
const audioBase64 = $input.item.json.audioContent;

if (!audioBase64) {
  return [{
    json: {
      error: '❌ audioContent не найден',
      fullResponse: $input.item.json
    }
  }];
}

console.log('✅ MP3 получен! Размер:', Math.round(audioBase64.length * 0.75 / 1024), 'KB');

return [
  {
    json: {
      _status: '✅ УСПЕХ! MP3 готов',
      sizeKB: Math.round(audioBase64.length * 0.75 / 1024)
    },
    binary: {
      data: {
        data: audioBase64,
        mimeType: 'audio/mpeg',
        fileName: 'tts_aiconic.mp3',
        fileExtension: 'mp3'
      }
    }
  }
];
